/// Total number of training sequences across all phases
pub fn total_sequences() -> usize {
    CORPUS.iter().map(|phase| phase.len()).sum()
}

/// Total number of phases
pub fn number_phases() -> usize {
    CORPUS.len()
}

/// Get a random sample from the corpus (uses uptime as entropy)
pub fn get_random_sample() -> &'static str {
    let total = total_sequences();
    if total == 0 {
        return "Hello world";
    }
    let index = (crate::time::uptime_mouse() as usize) % total;
    let mut remaining = index;
    for phase in CORPUS {
        if remaining < phase.len() {
            return phase[remaining];
        }
        remaining -= phase.len();
    }
    CORPUS[0][0]
}

/// Get phase name
pub fn phase_name(phase: usize) -> &'static str {
        // Pattern matching — Rust's exhaustive branching construct.
match phase {
        0 => "Byte Patterns",
        1 => "Simple Sentences",
        2 => "Shell Commands",
        3 => "Q&A Pairs",
        4 => "Self-Knowledge",
        5 => "Conversations",
        6 => "Technical Knowledge",
        7 => "Ethics & Values",
        8 => "Reasoning Chains",
        9 => "Meta-Learning",
        _ => "Unknown",
    }
}